import{_ as s,o as t,c as o,a2 as p}from"./chunks/framework.BS3ZfcoS.js";const u=JSON.parse('{"title":"工作周记","description":"","frontmatter":{"title":"工作周记","author":"","collection":"职场成长","series_order":2,"total_chars":8393},"headers":[],"relativePath":"career/weekly.md","filePath":"career/weekly.md"}'),r={name:"career/weekly.md"};function e(n,a,h,l,i,g){return t(),o("div",null,[...a[0]||(a[0]=[p('<div class="page-toc"><p class="page-toc-title">📑 本页目录</p><a href="#s-267" class="page-toc-link">工作周记</a>     <a href="#s-268" class="page-toc-link">当我跳出职场，才发现普通人在职场上的很多事都被教错了</a>     <a href="#s-270" class="page-toc-link">普通人在职场被教错的事：过于听从别人的建议</a>     <a href="#s-272" class="page-toc-link">裸辞一年后 曾经没能解决的职场问题正中我的眉心</a>     <a href="#s-274" class="page-toc-link">爱吃亏的人有亏吃，职场老实人如何才能不被欺负？</a>     <a href="#s-276" class="page-toc-link">千万别做&quot;职场王宝钏&quot;，多思考自己的发展</a>     <a href="#s-278" class="page-toc-link">讨好型人格进，作为曾经严重的讨好型人格，我是如何摆脱的？</a>     <a href="#s-283" class="page-toc-link">其实你不是懒，而是过度疲劳了</a>     <a href="#s-284" class="page-toc-link">你只有一生，但是你会活很多次，因为七年就是一辈子</a>     <a href="#s-286" class="page-toc-link">30年前的乔布斯如何预言了今天的世界</a>     <a href="#s-288" class="page-toc-link">北京工作了7年，我为什么要离开？</a>     <a href="#s-289" class="page-toc-link">&quot;要有跟随你内心和直觉的勇气&quot; 乔布斯20年前最好的一次演讲</a>     <a href="#s-291" class="page-toc-link">那些20岁很在意30岁无所谓的事，关于人际、事业和自我成长</a>     <a href="#s-292" class="page-toc-link">家可以常回，但不能久待 | 和故乡的非正式和解</a>     <a href="#s-293" class="page-toc-link">打工人不语只是一味发疯，如何无痛上班？</a>     <a href="#s-295" class="page-toc-link">少年心气是不可再生之物？失去的心气再一点点滋养出来</a>     <a href="#s-296" class="page-toc-link">你不是变笨了，只是认知过载了</a>     <a href="#s-297" class="page-toc-link">幸福是一种能力，建议尽快解决不舒服的小事</a>     <a href="#s-299" class="page-toc-link">人生书单：成长/搞钱/沟通/规划 | 当我把AI调教成阅读教练</a>     <a href="#s-300" class="page-toc-link">被小团队孤立了怎么办？人品好还被孤立，也许是你变强的开始</a>     <a href="#s-301" class="page-toc-link">普通人一定要有「你时间很贵」的意识，高效P人无痛时间管理</a>     <a href="#s-302" class="page-toc-link">野心勃勃但缺乏动力的人一定要看看这期视频 | 建立个人系统人生真的会开挂</a>     <a href="#s-303" class="page-toc-link">我一直觉得，夏天是个会让命运加速的季节</a>     <a href="#s-306" class="page-toc-link">怎样使自己处于高能量状态？一些托举自己的tips</a>     <a href="#s-308" class="page-toc-link">能量低是因为你太爱思考了 | 一起读《当下的力量》</a>     <a href="#s-309" class="page-toc-link">看完放下社交焦虑，向上社交落落大方的秘诀 | 读《别独自用餐》</a>     <a href="#s-311" class="page-toc-link">反应慢、不会聊天接话的人一定要看这期视频 | 读《超级沟通者》</a>     <a href="#s-313" class="page-toc-link">光速恢复能量的有效休息法 | 为什么有些人面对压力能从容解决问题？</a>     <a href="#s-314" class="page-toc-link">性格扭扭捏捏的人都有一个特质，社恐不会聊天接话必看</a>     <a href="#s-315" class="page-toc-link">比痛经更折磨女性的是PMS，情绪崩溃自救指南</a>     <a href="#s-316" class="page-toc-link">不要让你的精气神被借走，心气没了的人一眼就能看出来</a>     <a href="#s-317" class="page-toc-link">为什么在城市待久了，再也融不进家乡？| 读《乡土中国》</a></div><h2 id="s-267" tabindex="-1">工作周记 <a class="header-anchor" href="#s-267" aria-label="Permalink to &quot;工作周记 {#s-267}&quot;">​</a></h2><p>共31个视频</p><h3 id="s-268" tabindex="-1">当我跳出职场，才发现普通人在职场上的很多事都被教错了 <a class="header-anchor" href="#s-268" aria-label="Permalink to &quot;当我跳出职场，才发现普通人在职场上的很多事都被教错了 {#s-268}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **职业发展不止升职加薪一条路，脱离公司平台也能与市场发生交易才是真正的职业自由</p><p>**2. **身边脱离传统雇佣关系的人出路大致有三类：线上创业、线下轻创业（技能散装售卖）、小圈子教练/咨询</p><h4 id="s-269" tabindex="-1">3. 职场环境正在去中心化——年轻人用脚投票、混合办公推行、远程协作成为常态 <a class="header-anchor" href="#s-269" aria-label="Permalink to &quot;3. 职场环境正在去中心化——年轻人用脚投票、混合办公推行、远程协作成为常态 {#s-269}&quot;">​</a></h4><p>**4. **理想的职业发展不是做到高管，而是找到自己喜欢的生活方式，并拥有跳出职场的底气</p><p><strong>金句</strong></p><p><em>「我特别想祝你有上岸的运气，也能有下岸的底气」</em></p><p><strong>行动指南</strong></p><p>培养至少一门脱离公司平台仍能独立变现的技能</p><h3 id="s-270" tabindex="-1">普通人在职场被教错的事：过于听从别人的建议 <a class="header-anchor" href="#s-270" aria-label="Permalink to &quot;普通人在职场被教错的事：过于听从别人的建议 {#s-270}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **社会标准绑架是大部分人痛苦的根源——25岁学有所成、30岁买房结婚、35岁做高管，这些时间节点不必照搬</p><p>**2. **做自己不是鸡汤，而是一种有效的获胜策略：当你的优势是自我特质的衍生，就没有人可以跟你竞争</p><h4 id="s-271" tabindex="-1">3. 品牌和个人一样，坚持做认为对的事、不盲目跟风，反而能形成差异化壁垒 <a class="header-anchor" href="#s-271" aria-label="Permalink to &quot;3. 品牌和个人一样，坚持做认为对的事、不盲目跟风，反而能形成差异化壁垒 {#s-271}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「你只有另辟蹊径，才能避开竞争。从本质上来看，与别人竞争是一种模仿」</em></p><p><strong>行动指南</strong></p><p>停止模仿他人的路径，找到自己独特的优势衍生方向并专注深耕</p><h3 id="s-272" tabindex="-1">裸辞一年后 曾经没能解决的职场问题正中我的眉心 <a class="header-anchor" href="#s-272" aria-label="Permalink to &quot;裸辞一年后 曾经没能解决的职场问题正中我的眉心 {#s-272}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **裸辞第一年像被&quot;切除四肢&quot;：前三个月失去固定收入，第二个三个月失去正常作息，第三个三个月失去稳定的信息网络，最后三个月失去清晰的社会身份认同</p><p>**2. **企业既剥削我们，也保护了我们的平庸和怠惰——脱离企业后，你本人就是唯一且最重要的生产力</p><h4 id="s-273" tabindex="-1">3. 身份认同决定行为模式，裸辞后最大的挑战是旧道路逐渐分离而新道路尚未找到 <a class="header-anchor" href="#s-273" aria-label="Permalink to &quot;3. 身份认同决定行为模式，裸辞后最大的挑战是旧道路逐渐分离而新道路尚未找到 {#s-273}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「某种程度上剥削了我们的企业，其实也保护了我们的平庸跟怠惰」</em></p><p><strong>行动指南</strong></p><p>裸辞前做充分准备；裸辞后要主动构建信息网络和新的身份认同，而非被动等待</p><h3 id="s-274" tabindex="-1">爱吃亏的人有亏吃，职场老实人如何才能不被欺负？ <a class="header-anchor" href="#s-274" aria-label="Permalink to &quot;爱吃亏的人有亏吃，职场老实人如何才能不被欺负？ {#s-274}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **善良必须带有锋芒，否则就会被强势者侵占边界；边界越明确，别人越会主动适应你的规则</p><h4 id="s-275" tabindex="-1">2. 温柔需要强大托底——拒绝消耗你的人事后，腾出的时间必须用来培育硬实力 <a class="header-anchor" href="#s-275" aria-label="Permalink to &quot;2. 温柔需要强大托底——拒绝消耗你的人事后，腾出的时间必须用来培育硬实力 {#s-275}&quot;">​</a></h4><p>**3. **强大不等于强势，珍惜自己身上的温柔与真诚——为了不被欺负把自己变成自己不喜欢的人，是对自己的霸凌</p><p><strong>金句</strong></p><p><em>「温柔的人不是没有脾气，而是他的内核足够强大，强大到自然而然溢出来的气场」</em></p><p><strong>行动指南</strong></p><p>练习拒绝不合理要求并明确边界；用省下的时间培育核心优势</p><h3 id="s-276" tabindex="-1">千万别做&quot;职场王宝钏&quot;，多思考自己的发展 <a class="header-anchor" href="#s-276" aria-label="Permalink to &quot;千万别做&quot;职场王宝钏&quot;，多思考自己的发展 {#s-276}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **职场王宝钏现象：通过自我剥削和压榨来维系一段不值得的职场关系，逻辑跟恋爱脑一模一样</p><p>**2. **长期被PUA的员工会产生斯德哥尔摩式自我合理化——&quot;公司没裁我已经对我很好了&quot;</p><h4 id="s-277" tabindex="-1">3. 在有害环境中待久了会丧失对自己能力的判断，不敢相信自己能找到更好的选择 <a class="header-anchor" href="#s-277" aria-label="Permalink to &quot;3. 在有害环境中待久了会丧失对自己能力的判断，不敢相信自己能找到更好的选择 {#s-277}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「这次都没有把我打出鼻血，他已经对我很好了，你知道现在谈恋爱有多难吗」</em></p><p><strong>行动指南</strong></p><p>客观评估自己的市场价值，拿现有成绩去找下一份工作，而非在消耗性关系中自我说服</p><h3 id="s-278" tabindex="-1">讨好型人格进，作为曾经严重的讨好型人格，我是如何摆脱的？ <a class="header-anchor" href="#s-278" aria-label="Permalink to &quot;讨好型人格进，作为曾经严重的讨好型人格，我是如何摆脱的？ {#s-278}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-279" tabindex="-1">1. 讨好者本质上也是控制狂——用被人控制的假象来控制别人不离开自己 <a class="header-anchor" href="#s-279" aria-label="Permalink to &quot;1. 讨好者本质上也是控制狂——用被人控制的假象来控制别人不离开自己 {#s-279}&quot;">​</a></h4><h4 id="s-280" tabindex="-1">2. 人际关系中的讨好是一种邀请，你邀请对方变得更自私、对你更缺乏同理心 <a class="header-anchor" href="#s-280" aria-label="Permalink to &quot;2. 人际关系中的讨好是一种邀请，你邀请对方变得更自私、对你更缺乏同理心 {#s-280}&quot;">​</a></h4><h4 id="s-281" tabindex="-1">3. 健康的离职不是因为逃跑，而是有清晰的规划去拿下一个阶段的职业结果 <a class="header-anchor" href="#s-281" aria-label="Permalink to &quot;3. 健康的离职不是因为逃跑，而是有清晰的规划去拿下一个阶段的职业结果 {#s-281}&quot;">​</a></h4><h4 id="s-282" tabindex="-1">4. 真正的朋友允许你做低情商的自己——优点人人都爱，缺点才能筛出谁真正爱你 <a class="header-anchor" href="#s-282" aria-label="Permalink to &quot;4. 真正的朋友允许你做低情商的自己——优点人人都爱，缺点才能筛出谁真正爱你 {#s-282}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「所有的人跟事你都可以失去，只有你自己是不可以失去的」</em></p><p><strong>行动指南</strong></p><p>分辨自己讨好的动机——是真心想做还是害怕失去；练习在关系中展现真实的自我</p><h3 id="s-283" tabindex="-1">其实你不是懒，而是过度疲劳了 <a class="header-anchor" href="#s-283" aria-label="Permalink to &quot;其实你不是懒，而是过度疲劳了 {#s-283}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **成年人生活最大的陷阱：长期在紧张人际关系和高压环境中浸泡，出色的人也会变得暗淡无光</p><p>**2. **千万不要长期让能量支出大于能量收入，主动给自己建立充能清单（物品、人类、场所三类）</p><p>**3. **做自己的老板——你是自己唯一的下属，必须提携、关爱、督促、勉励自己，对自己全权负责</p><p><strong>金句</strong></p><p><em>「做自己的老板，我是我自己唯一的下属，意味着我必须要提携、关爱、督促、勉励自己」</em></p><p><strong>行动指南</strong></p><p>列出10项让你快乐充能的事项（分物品、人类、场所三栏），能量低时主动使用</p><h3 id="s-284" tabindex="-1">你只有一生，但是你会活很多次，因为七年就是一辈子 <a class="header-anchor" href="#s-284" aria-label="Permalink to &quot;你只有一生，但是你会活很多次，因为七年就是一辈子 {#s-284}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **人体细胞每七年全部更新一次，每个人生阶段有自己的&quot;活法&quot;和功课，用旧阶段的规则套新世界会出问题</p><p>**2. **人生危机的本质是课本和考卷已经换了，但人没意识到——170的个子还在穿150的衣服</p><h4 id="s-285" tabindex="-1">3. 重生的关键第一步是敢于让旧角色&quot;死掉&quot;，不断学习新技能、拥抱新身份 <a class="header-anchor" href="#s-285" aria-label="Permalink to &quot;3. 重生的关键第一步是敢于让旧角色&quot;死掉&quot;，不断学习新技能、拥抱新身份 {#s-285}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「你活一辈子不是为了要给别人打工，而是为了活成自己喜欢的样子」</em></p><p><strong>行动指南</strong></p><p>问自己&quot;我现在是否已经到了新阶段但还在用旧规则？&quot;——如有，列出需要更新的知识和实践</p><h3 id="s-286" tabindex="-1">30年前的乔布斯如何预言了今天的世界 <a class="header-anchor" href="#s-286" aria-label="Permalink to &quot;30年前的乔布斯如何预言了今天的世界 {#s-286}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **顶尖高手的共同特质：极有远见，且从认知到落地的间隔极短（乔布斯预见网购、马斯克用第一性原理造火箭）</p><p>**2. **第一性原理思维：将假设推至源头寻求本质洞察，删除非本质的结构和部件——提升价值创造能力而非追求升职加薪</p><h4 id="s-287" tabindex="-1">3. 把打动你的精神放进你的产品里——什么拯救过你，你就拿它来拯救世界 <a class="header-anchor" href="#s-287" aria-label="Permalink to &quot;3. 把打动你的精神放进你的产品里——什么拯救过你，你就拿它来拯救世界 {#s-287}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「你应该把打动你的那种精神放到你的产品里」</em></p><p><strong>行动指南</strong></p><p>找到自己工作和创作的&quot;精神内核&quot;，让产品/内容围绕这个内核而非外界的潮流运转</p><h3 id="s-288" tabindex="-1">北京工作了7年，我为什么要离开？ <a class="header-anchor" href="#s-288" aria-label="Permalink to &quot;北京工作了7年，我为什么要离开？ {#s-288}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **年轻时在多元城市生活能打开活法的想象力——Plan A失效时，你知道Plan B/C/D依然有效</p><p>**2. **人无法脱离时代生存，每次选择忠于内心而内心需求恰好吻合时代变化，才是最大的幸运</p><p>**3. **真正长在身上的能力：工作量大导致的高耐受力、对不确定性的高容忍度、紧绷的上进心——但紧绷不能影响健康</p><p><strong>金句</strong></p><p><em>「人没有办法脱离时代生存，每个人都是活着的历史」</em></p><p><strong>行动指南</strong></p><p>盘点哪些能力是长在自己身上、不依托平台的；关注内心的召唤而非仅算利益</p><h3 id="s-289" tabindex="-1">&quot;要有跟随你内心和直觉的勇气&quot; 乔布斯20年前最好的一次演讲 <a class="header-anchor" href="#s-289" aria-label="Permalink to &quot;&quot;要有跟随你内心和直觉的勇气&quot; 乔布斯20年前最好的一次演讲 {#s-289}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **连点成线：你无法站在起点构思未来，只有一直走、回头看时才能把点连起来——不要怕落点</p><h4 id="s-290" tabindex="-1">2. 真正热爱的两个标志：做的时候有心流深度专注；即便不挣钱也觉得有意义 <a class="header-anchor" href="#s-290" aria-label="Permalink to &quot;2. 真正热爱的两个标志：做的时候有心流深度专注；即便不挣钱也觉得有意义 {#s-290}&quot;">​</a></h4><p>**3. **真正的问题不是不知道自己想要什么，而是内心知道但不敢听从，因为怕自己错了、怕别人不支持</p><p><strong>金句</strong></p><p><em>「你得找到你爱的事，这就是真正的工作」</em></p><p><strong>行动指南</strong></p><p>每天问自己&quot;假如今天是我生命中的最后一天，我还会去做今天要做的事吗？&quot;——连答多天&quot;不&quot;就该改变</p><h3 id="s-291" tabindex="-1">那些20岁很在意30岁无所谓的事，关于人际、事业和自我成长 <a class="header-anchor" href="#s-291" aria-label="Permalink to &quot;那些20岁很在意30岁无所谓的事，关于人际、事业和自我成长 {#s-291}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **从消耗你的人际中撤退——你越想用善意化解对方的恶意，越难脱身；关注点应在自己身上</p><p>**2. **职业上的撤退：与其做十件价值一万的事，不如把一件事做到十万的价值——不是那件事是最好的选择，而是你的坚持让它成为最好的选择</p><p>**3. **从自我批判中撤退——把自己看作一组参数，擅长和不擅长只是数值差异，不支持就调整，而非攻击自身</p><p><strong>金句</strong></p><p><em>「不是那件事本身是最好的选择，而是你的坚持让它成为了最好的选择」</em></p><p><strong>行动指南</strong></p><p>写下&quot;不想要清单&quot;，从中反向推导真正想要的；从多余目标中撤退，聚焦主战场</p><h3 id="s-292" tabindex="-1">家可以常回，但不能久待 | 和故乡的非正式和解 <a class="header-anchor" href="#s-292" aria-label="Permalink to &quot;家可以常回，但不能久待 | 和故乡的非正式和解 {#s-292}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **城市是陌生人社会——孤独但自由，独特的自我有空间喘息成长；故乡是熟人社会——亲密但窒息，职业选择被窄化</p><p>**2. **最高级的和解是&quot;非整合&quot;：允许两种真相永久共存——永远不可能成为故乡期待的样子，同时永远珍藏童年赤脚在山坡风跑的快乐</p><p>**3. **放弃修改——不要试图改变父母和故乡，也不必强行大和解，承认创伤同时也看见它带来的力量</p><p><strong>金句</strong></p><p><em>「面对过去，我们不要只是看见缺陷，还要看见力量」</em></p><p><strong>行动指南</strong></p><p>练习&quot;非整合&quot;思维，承认故乡两种真相的同时存在，不再强求单一态度</p><h3 id="s-293" tabindex="-1">打工人不语只是一味发疯，如何无痛上班？ <a class="header-anchor" href="#s-293" aria-label="Permalink to &quot;打工人不语只是一味发疯，如何无痛上班？ {#s-293}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **负面情绪是信号：厌倦提醒创造变化，焦虑提示能力需加固，失落代表价值观需求未满足</p><p>**2. **降低预期和应该思维——有意义还赚钱的好工作很稀缺，大部分工作就是谋生加社会装饰</p><h4 id="s-294" tabindex="-1">3. 以终为始看待当前工作：如果一年后要离开，我要带走什么？ <a class="header-anchor" href="#s-294" aria-label="Permalink to &quot;3. 以终为始看待当前工作：如果一年后要离开，我要带走什么？ {#s-294}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「我们登上并非我们所选择的舞台，演绎并非我们所选择的剧本，职场身份也只是命运分配的角色，尽力演好但不要太入戏」</em></p><p><strong>行动指南</strong></p><p>用&quot;三信号法&quot;分辨负面情绪背后的需求；降低对工作的期待，关注自己能带走什么</p><h3 id="s-295" tabindex="-1">少年心气是不可再生之物？失去的心气再一点点滋养出来 <a class="header-anchor" href="#s-295" aria-label="Permalink to &quot;少年心气是不可再生之物？失去的心气再一点点滋养出来 {#s-295}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **失去心气是对世界和自我的&quot;去魅&quot;——成年后的真相不再是无限可能，而是努力了结果也不过如此</p><p>**2. **少年心气有两种：借来的（青春年少时免费的馈赠，终将消逝）和挣的（主动对抗熵增、不依赖年龄的心气）</p><p>**3. **在小事上保持心气，才能在大事上也不失去心气——精神熵是注定溃散的，除非主动对抗</p><p><strong>金句</strong></p><p><em>「我并不灰心……我看到了北海的垂柳，之后悬挂着晶莹的冰柱」</em></p><p><strong>行动指南</strong></p><p>每天做一件小事保持心气（早起学习、坚持创作、参加活动），用小胜利滋养内在动力</p><h3 id="s-296" tabindex="-1">你不是变笨了，只是认知过载了 <a class="header-anchor" href="#s-296" aria-label="Permalink to &quot;你不是变笨了，只是认知过载了 {#s-296}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **认知过载的表现：信息多但形不成观点、明知道该做却无法集中、持续拖延、脑子雾蒙蒙</p><p>**2. **停止错误休息——刷手机和追剧加重大脑负担。感官过载需要感官型休息（降低光线、远离人群、独处），精神疲倦需要认知型休息（卸载短视频、闭关朋友圈）</p><p>**3. **减少非重要决策的算力消耗：买20双一样的袜子、高情商回复甩给AI润色——省下脑力主动思考，从被动吸收者变成主动搜索者</p><p><strong>金句</strong></p><p><em>「此刻我已经足够完美，我不需要把每件事都做好才能证明我是个有价值的人」</em></p><p><strong>行动指南</strong></p><p>低精力时用感官休息，脑力疲惫时用认知休息；将低优先级决策外包或选默认值；阶段性卸载短视频App改为主动搜索</p><h3 id="s-297" tabindex="-1">幸福是一种能力，建议尽快解决不舒服的小事 <a class="header-anchor" href="#s-297" aria-label="Permalink to &quot;幸福是一种能力，建议尽快解决不舒服的小事 {#s-297}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **尽快解决让不舒服的小事——两分钟原则：两分钟内能解决的立刻执行，避免小问题堆积成内心阻力</p><h4 id="s-298" tabindex="-1">2. 把不舒服的事舒服地做——降低启动难度、结合性格人性、哄自己开开心心地做事 <a class="header-anchor" href="#s-298" aria-label="Permalink to &quot;2. 把不舒服的事舒服地做——降低启动难度、结合性格人性、哄自己开开心心地做事 {#s-298}&quot;">​</a></h4><p>**3. **幸福本质上是管理注意力的能力——生活从来不是单纯的好与坏，你的感受取决于注意力放在哪</p><p><strong>金句</strong></p><p><em>「不要置之不理自己的微小需求」</em></p><p><strong>行动指南</strong></p><p>立刻解决一个拖延已久的小不适；列出&quot;难受但2分钟能搞定的事&quot;逐一清掉；有意识地将注意力导向积极版图</p><h3 id="s-299" tabindex="-1">人生书单：成长/搞钱/沟通/规划 | 当我把AI调教成阅读教练 <a class="header-anchor" href="#s-299" aria-label="Permalink to &quot;人生书单：成长/搞钱/沟通/规划 | 当我把AI调教成阅读教练 {#s-299}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **社会适应早期必须通过阅读建立强者自救意识——强势文化遵循规律，弱势文化等靠要</p><p>**2. **经济基础决定上层建筑，金钱观教育的缺失让年轻人仇富或陷入稀缺循环——先脱贫再自由</p><p>**3. **AI可成为高效阅读教练：指路（问问题获方向）、伴读（解读难点）、知识代谢（生成卡片和框架）</p><p><strong>金句</strong></p><p><em>「我很想要得到预想的结果，一定要使自己的思想合乎于外界的规律性，如果不合就会在实践中失败」</em></p><p><strong>行动指南</strong></p><p>按四个阶段搭建书单（强者思维→脱贫→沟通→规划），用AI辅助阅读和知识内化</p><h3 id="s-300" tabindex="-1">被小团队孤立了怎么办？人品好还被孤立，也许是你变强的开始 <a class="header-anchor" href="#s-300" aria-label="Permalink to &quot;被小团队孤立了怎么办？人品好还被孤立，也许是你变强的开始 {#s-300}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **被动型攻击（Passive Aggressive）比主动攻击更难识别：礼貌推锅、信息垄断、含糊沟通——你感到不舒服但找不到把柄</p><p>**2. **人品好还被孤立，可能是因为你的存在让安于现状的人不安——你不是做错了什么，而是你变强了</p><p>**3. **某些情况下你确实是别人眼中的威胁——理解这一点后从&quot;我为什么被针对&quot;转向&quot;我要去更适合我的环境&quot;</p><p><strong>金句</strong></p><p><em>「那些你说不清道不明的恶意，如果你感受到了，那就是真实的」</em></p><p><strong>行动指南</strong></p><p>识别被动型攻击模式，不再给自己贴&quot;小心眼&quot;标签；提升实力去到更高层次的环境</p><h3 id="s-301" tabindex="-1">普通人一定要有「你时间很贵」的意识，高效P人无痛时间管理 <a class="header-anchor" href="#s-301" aria-label="Permalink to &quot;普通人一定要有「你时间很贵」的意识，高效P人无痛时间管理 {#s-301}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **时间管理能力本质不是执行力而是判断力——目标不是做更多事，而是做更少的事撬动更大价值</p><p>**2. **先写&quot;不想要清单&quot;而非&quot;想要清单&quot;，不想要的动力更强，想要清单也会随之浮现</p><p>**3. **策略性拖延：有些活拖着拖着就没了——决定不做什么跟决定做什么同样重要；授权和AI外包节省非核心算力</p><p><strong>金句</strong></p><p><em>「决定不做什么跟决定做什么同样重要」</em></p><p><strong>行动指南</strong></p><p>列出&quot;不想要清单&quot;，对低价值任务策略性拖延或授权/AI外包；聚焦高杠杆的少数事项</p><h3 id="s-302" tabindex="-1">野心勃勃但缺乏动力的人一定要看看这期视频 | 建立个人系统人生真的会开挂 <a class="header-anchor" href="#s-302" aria-label="Permalink to &quot;野心勃勃但缺乏动力的人一定要看看这期视频 | 建立个人系统人生真的会开挂 {#s-302}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **人有两种系统：混沌系统（目标多反复推翻、浅尝辄止、时间流逝还是新手）和复利系统（路径越走越清晰、付出获得叠加效应）</p><p>**2. **复利系统第一步是找到&quot;价值原点&quot;——就算做三年也没大火，只要守护好原点，你已是内容的第一个受益人</p><p>**3. **在自己身上长出确定性——当身边人在迷茫纠结中挣扎时，你靠系统而非运气前进，时间就是你的朋友</p><p><strong>金句</strong></p><p><em>「生活中所有的回报，不论是财富、人际关系还是知识，都来自复利」</em></p><p><strong>行动指南</strong></p><p>找到自己的价值原点并长期守护；建立一套可迭代的个人系统，减少重复决策</p><h3 id="s-303" tabindex="-1">我一直觉得，夏天是个会让命运加速的季节 <a class="header-anchor" href="#s-303" aria-label="Permalink to &quot;我一直觉得，夏天是个会让命运加速的季节 {#s-303}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-304" tabindex="-1">1. 夏天是让命运加速的季节——很多重要的人生节点都发生在夏天 <a class="header-anchor" href="#s-304" aria-label="Permalink to &quot;1. 夏天是让命运加速的季节——很多重要的人生节点都发生在夏天 {#s-304}&quot;">​</a></h4><h4 id="s-305" tabindex="-1">2. 年中时间点让人清醒：今年已过半，想做的没做的都会被摊开 <a class="header-anchor" href="#s-305" aria-label="Permalink to &quot;2. 年中时间点让人清醒：今年已过半，想做的没做的都会被摊开 {#s-305}&quot;">​</a></h4><p>**3. **在很年轻时就找到热爱的事业是极大的幸运，与创作相伴的时光像一场漫长的从未褪色的恋情</p><p><strong>金句</strong></p><p><em>「对我的视野爱久弥新，希望大家也可以找到爱久弥新的人跟事」</em></p><p><strong>行动指南</strong></p><p>在夏天勇敢推进拖延已久的事；年中做一次清醒的盘点和调整</p><h3 id="s-306" tabindex="-1">怎样使自己处于高能量状态？一些托举自己的tips <a class="header-anchor" href="#s-306" aria-label="Permalink to &quot;怎样使自己处于高能量状态？一些托举自己的tips {#s-306}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **人的两种模式：自我压榨模式（社会功能凌驾于做人需要）vs 自我支持模式；高手在事业巅峰期反而格外重视身心系统稳定</p><p>**2. **幸福四大激素可自我干预：多巴胺（完成小任务+新鲜感+自我奖励）、内啡肽（大笑运动泡温泉）、催产素（拥抱亲吻宠物社交）、血清素（阳光散步规律作息）</p><h4 id="s-307" tabindex="-1">3. 一个人能走多远取决于身体和情绪的续航能力 <a class="header-anchor" href="#s-307" aria-label="Permalink to &quot;3. 一个人能走多远取决于身体和情绪的续航能力 {#s-307}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「一个人能走多远，取决于他身体和情绪的续航能力」</em></p><p><strong>行动指南</strong></p><p>对照四类激素缺哪种补哪种；记录身体感受和情绪变化，用AI分析自己的状态模式</p><h3 id="s-308" tabindex="-1">能量低是因为你太爱思考了 | 一起读《当下的力量》 <a class="header-anchor" href="#s-308" aria-label="Permalink to &quot;能量低是因为你太爱思考了 | 一起读《当下的力量》 {#s-308}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **痛苦之身：过去未被解决的委屈聚在一起形成能量怪兽，一旦被刺激就醒来接管大脑——你痛苦时是过去所有痛苦在共鸣</p><p>**2. **思维认同：把脑海中的念头当事实——坏事还没发生你就先焦虑了一遍，等于受了两次苦</p><p>**3. **完全臣服于此时此刻才能释放能量：把宏大目标分解成当下的小动作，只专注眼前这一步</p><p><strong>金句</strong></p><p><em>「坏事还没发生，但你先焦虑了一遍，你就相当于受了两次苦」</em></p><p><strong>行动指南</strong></p><p>觉察痛苦之身的激活模式；拒绝与脑海中的坏念头&quot;攀谈&quot;，让它自己离开；将大目标分解为当下可执行的小动作</p><h3 id="s-309" tabindex="-1">看完放下社交焦虑，向上社交落落大方的秘诀 | 读《别独自用餐》 <a class="header-anchor" href="#s-309" aria-label="Permalink to &quot;看完放下社交焦虑，向上社交落落大方的秘诀 | 读《别独自用餐》 {#s-309}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-310" tabindex="-1">1. 向上社交始于给予——你认识的人不是你的人脉，你能帮到的人才是你的人脉 <a class="header-anchor" href="#s-310" aria-label="Permalink to &quot;1. 向上社交始于给予——你认识的人不是你的人脉，你能帮到的人才是你的人脉 {#s-310}&quot;">​</a></h4><p>**2. **理解上位者心理：他们骄傲但内心缺乏安全感、被阿谀奉承包围、缺少时间——真诚看见他们的具体需求而非追捧公众形象</p><p>**3. **暴露脆弱是人际关系的二次筛纯——讨好型人格留下的朋友爱的是你的工具性，展现真性情留下的才是真朋友</p><p><strong>金句</strong></p><p><em>「你认识的人不是你的人脉，你能帮到的人才是你的人脉」</em></p><p><strong>行动指南</strong></p><p>主动思考你能为对方提供什么（时间、专业能力、知识）；在关系中适度暴露真正的需求而非伪装</p><h3 id="s-311" tabindex="-1">反应慢、不会聊天接话的人一定要看这期视频 | 读《超级沟通者》 <a class="header-anchor" href="#s-311" aria-label="Permalink to &quot;反应慢、不会聊天接话的人一定要看这期视频 | 读《超级沟通者》 {#s-311}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **所有对话本质只有三种类型：务实对话（逻辑/方案）、情感对话（被看见/理解）、社交对话（找同频）；90%沟通失败是频道不匹配</p><p>**2. **超级沟通者提问频率是普通人10-20倍——他们不是话最多的人，而是最会提问的人</p><h4 id="s-312" tabindex="-1">3. 循环理解型提问三步法：开放性提问→复述对方内容→确认理解后再深化 <a class="header-anchor" href="#s-312" aria-label="Permalink to &quot;3. 循环理解型提问三步法：开放性提问→复述对方内容→确认理解后再深化 {#s-312}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「沟通不是一种性格，而是一种可复制的能力」</em></p><p><strong>行动指南</strong></p><p>对话前先判断对方在进行哪种对话类型；练习循环理解型提问；对话中多问少断</p><h3 id="s-313" tabindex="-1">光速恢复能量的有效休息法 | 为什么有些人面对压力能从容解决问题？ <a class="header-anchor" href="#s-313" aria-label="Permalink to &quot;光速恢复能量的有效休息法 | 为什么有些人面对压力能从容解决问题？ {#s-313}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **压力不是情绪而是剧烈的生理活动——斑马的压力开关在狮子走后关闭，人类的开关因想象中的狮子而永远开着</p><p>**2. **长期高皮质醇是毒药：攻击海马体（健忘变笨）、囤积热量（压力肥）、引发全身性炎症</p><p>**3. **身体是内心的剧场——心理压力会迅速在外部身体表现出来，30岁后身体报警信号更明显</p><p><strong>金句</strong></p><p><em>「人类是唯一一种会自己吓自己的动物，我们的大脑分不清真假狮子」</em></p><p><strong>行动指南</strong></p><p>学会关闭压力开关——通过运动、冥想、社交支持主动降低皮质醇；关注身体信号，不要等到崩溃才休息</p><h3 id="s-314" tabindex="-1">性格扭扭捏捏的人都有一个特质，社恐不会聊天接话必看 <a class="header-anchor" href="#s-314" aria-label="Permalink to &quot;性格扭扭捏捏的人都有一个特质，社恐不会聊天接话必看 {#s-314}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **社交扭捏的本质是&quot;自我监控过剩&quot;——注意力全指向&quot;我够不够格、我该怎么被看&quot;，没有一种审判比自我审判更残酷</p><p>**2. **自觉矜贵不是傲慢而是自我托举——你作为人的存在本身就有价值，大佬寻找的是内核稳定不卑不亢的人</p><p>**3. **社交不是考试是筛选——不是对方在给你打分，而是你们互相确认适不适合发生连接</p><p><strong>金句</strong></p><p><em>「自觉矜贵不是自傲，而是对自己的尊重和认可；一个人对自己的爱足够了，她就不会一直巴望别人的爱和认可」</em></p><p><strong>行动指南</strong></p><p>社交时把注意力从&quot;我怎么被看&quot;转向&quot;我们是否匹配&quot;；见到厉害的人不卑不亢，展现内核自信</p><h3 id="s-315" tabindex="-1">比痛经更折磨女性的是PMS，情绪崩溃自救指南 <a class="header-anchor" href="#s-315" aria-label="Permalink to &quot;比痛经更折磨女性的是PMS，情绪崩溃自救指南 {#s-315}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **女性每月有两套操作系统在切换：雌激素期（精力充沛社交欲强）和孕酮期（倾向独处、对危险过度警觉）</p><p>**2. **现代生活（慢性压力、睡眠不足、加工食品导致慢性炎症）干扰了孕酮期天然安定物质&quot;别孕烯醇酮&quot;的正常运转，只留焦虑没有平静</p><p>**3. **PMS严重程度更多取决于当月的炎症基线而非激素本身——抗炎才是30+女性的人生大事</p><p><strong>金句</strong></p><p><em>「不是你变了，而是你的身体在执行不同的任务」</em></p><p><strong>行动指南</strong></p><p>黄体期不刻意节食，增加优质蛋白和抗炎食物摄入、降低运动强度、保证睡眠；月经前不做重大关系决策</p><h3 id="s-316" tabindex="-1">不要让你的精气神被借走，心气没了的人一眼就能看出来 <a class="header-anchor" href="#s-316" aria-label="Permalink to &quot;不要让你的精气神被借走，心气没了的人一眼就能看出来 {#s-316}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **精气神好的人不是遇到的事少，而是精气神没有被借走——他们的能量是往外流动的，整个人活在自己的身体里</p><p>**2. **信息暴饮暴食的可怕不在浪费时间，而在长期消化别人的人生——你自己的人生该怎么交代？</p><p>**3. **深度共情别人后要有能力把意识收回来——回到家要正式从别人的意识和社会意识中走出来，把自己的意识接回来</p><p><strong>金句</strong></p><p><em>「现代年轻人最大的精神症状，就是自己缺席自己的生活」</em></p><p><strong>行动指南</strong></p><p>注重&quot;用脑卫生&quot;，减少低质信息摄入；每天留出向内关注身体的时间；睡前做意识回收的仪式</p><h3 id="s-317" tabindex="-1">为什么在城市待久了，再也融不进家乡？| 读《乡土中国》 <a class="header-anchor" href="#s-317" aria-label="Permalink to &quot;为什么在城市待久了，再也融不进家乡？| 读《乡土中国》 {#s-317}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **中国社会基层是乡土性的——土地锁住人，形成&quot;熟人社会&quot;：人人彼此知根知底，面子是最重要的社会资产</p><p>**2. **差序格局：中国人的关系网像石子入水的涟漪，以自己为圆心层层扩散，不同圈层有不同义务，办事找关系本质是圈内逻辑</p><p>**3. **礼治秩序的核心是长老统治——谁年长辈高谁有规矩解释权，餐桌座次敬酒规则都是权力等级的演练；女性在这个体系中天然处于不利位置</p><p><strong>金句</strong></p><p><em>「每一种人生都是完整的打包，你没有办法只取你想要的部分，那些不想要的部分是连带的」</em></p><p><strong>行动指南</strong></p><p>理解乡土逻辑的合理性但不被其束缚；走出差序格局需要的不是否定来处，而是在城市中建立新的关系范式</p>',284)])])}const q=s(r,[["render",e]]);export{u as __pageData,q as default};
